var CryptoJS = require('crypto-js');


window = global;

js_Code

function decrypt_data(encrypt_data, encode, id) {
    var key = eval('window.' + id)
    console.log(key);
    switch (encode) {
        case 3:
            key = key["split"]("")["reverse"]()["join"]("")
            break;
        case 4:
            key = key["slice"](2)
            break;
        case 5:
            key = key["slice"](0, key["length"] - 2)
            break;
        case 6:
            key = key["slice"](1, key["length"] - 1)
            break;
        case 7:
            key = key["slice"](2, key["length"] - 1)
            break;
        case 8:
            key = key["slice"](2, key["length"] - 1)
            break;
        case 9:
            key = key[0] + key["slice"](2, key["length"])
            break;
        case 10:
            key = key["slice"](0, key["length"] - 2) + key[key["length"] - 1]
            break;
    }
    var e = CryptoJS.MD5(key).toString()
    var t = CryptoJS.enc.Utf8["parse"](e)
    var r = CryptoJS.enc.Utf8["parse"](e.slice(16, 32))
    var n = CryptoJS.AES["decrypt"](atob(encrypt_data), t, {
        iv: r,
        padding: CryptoJS.pad.Pkcs7
    }).toString(CryptoJS.enc.Utf8);
    return n;
}

